```hcl
# Terraform: Ensure ASG uses multiple instance types across multiple AZs
resource "aws_autoscaling_group" "<example_resource_name>" {
  name               = "<example_resource_name>"
  min_size           = 1
  max_size           = 1
  vpc_zone_identifier = ["<subnet_id_1>", "<subnet_id_2>"] # CRITICAL: Subnets in different AZs

  mixed_instances_policy {
    launch_template {
      launch_template_specification {
        launch_template_name = "<example_resource_name>"
        version              = "$Latest"
      }
      override { instance_type = "<INSTANCE_TYPE_1>" } # CRITICAL: Multiple instance types per AZ
      override { instance_type = "<INSTANCE_TYPE_2>" } # CRITICAL: Multiple instance types per AZ
    }
  }
}
```

```hcl
# Terraform: attach a Launch Template to the ASG
resource "aws_autoscaling_group" "example" {
  min_size            = 0
  max_size            = 1
  vpc_zone_identifier = ["<example_subnet_id>"]

  launch_template {
    id      = "<example_launch_template_id>" # critical: ensures the ASG uses an EC2 launch template (fixes the check)
    version = "$Default"
  }
}
```

```hcl
# Terraform: ensure ASG spans multiple AZs
resource "aws_autoscaling_group" "<example_resource_name>" {
  min_size = 1
  max_size = 1

  launch_template {
    id      = "<example_resource_id>"
    version = "$Latest"
  }

  vpc_zone_identifier = [
    "<subnet_id_az1>",
    "<subnet_id_az2>" # CRITICAL: two subnets in different AZs to pass the check
  ]
}
```

```hcl
# ASG launch configuration enforces IMDSv2
resource "aws_launch_configuration" "example" {
  image_id      = "<example_ami_id>"
  instance_type = "<example_instance_type>"

  metadata_options {
    http_tokens   = "required"  # critical: require IMDSv2 tokens (blocks IMDSv1)
    http_endpoint = "enabled"   # critical: IMDS enabled while enforcing v2
  }
}

resource "aws_autoscaling_group" "example" {
  launch_configuration = aws_launch_configuration.example.name
  min_size             = 1
  max_size             = 1
  vpc_zone_identifier  = ["<example_subnet_id>"]
}
```
